// Gate: Yên đã set chosen_option. Lấy caption + visual của option đó.
const p = $json.properties;
const txt = (rt) => (rt && rt[0] && rt[0].plain_text) || "";
const chosen = p.chosen_option?.select?.name;
let options = [];
try { options = JSON.parse(txt(p.options_json?.rich_text) || '[]'); } catch (e) {}
const opt = options.find(o => o.label === chosen) || options[0] || {};
const now = new Date();
const due = new Date(now.getTime() + 48*60*60*1000).toISOString().slice(0,10);
return {
  page_id: $json.id,
  post_id: txt(p.post_id.title),
  platform: (p.platforms?.multi_select || []).map(o => o.name).join('+'),
  chosen,
  caption: opt.caption || '',
  visual: opt.visual || null,
  human_score: opt.human_score ?? null,
  er_check_due: due
};

// ⚠️ TODO — ĐĂNG BÀI: thay bằng call Meta Graph / LinkedIn API thật.
// Input có: caption, visual.template, visual.model, platform, post_id.
// Tạm đánh dấu published để test luồng.
return { ...$json, publish_note: 'TODO: nối Meta/LinkedIn API. Caption + visual đã sẵn ở input.' };

